'use client';

import Image from 'next/image';
import { motion } from 'framer-motion';
import { SectionHeading } from '@/components/ui/SectionHeading';
import { Button } from '@/components/ui/Button';
import { galleryImages } from '@/data/gallery';

export function FeaturedGallery() {
  // Take 4 images for a distinct asymmetric grid
  const featured = galleryImages.slice(0, 4);

  return (
    <section className="py-24 bg-dark-900 border-t border-dark-800">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <SectionHeading
          subtitle="Portfolio"
          title="Featured Artistry"
          description="Explore our finest and most intricate mehendi designs from recent celebrations."
        />

        {/* Asymmetrical Floating Gallery Grid */}
        <div className="mt-16 grid grid-cols-1 md:grid-cols-12 gap-6 md:auto-rows-[300px]">
          {featured.map((image, index) => {
            // Create an asymmetrical layout based on index
            let gridClass = "";
            let animDelay = index * 0.15;

            if (index === 0) {
              gridClass = "md:col-span-7 md:row-span-2"; // Large feature
            } else if (index === 1) {
              gridClass = "md:col-span-5 md:row-span-1"; // Wide top right
            } else if (index === 2) {
              gridClass = "md:col-span-3 md:row-span-1"; // Small square
            } else {
              gridClass = "md:col-span-2 md:row-span-1 hidden md:block"; // Small square (hidden on mobile to balance)
            }

            return (
              <motion.div
                key={image.id}
                initial={{ opacity: 0, scale: 0.95 }}
                whileInView={{ opacity: 1, scale: 1 }}
                viewport={{ once: true, margin: "-50px" }}
                transition={{ duration: 0.8, delay: animDelay, ease: "easeOut" }}
                className={`group relative overflow-hidden rounded-sm border border-dark-700 hover:border-accent-gold/40 transition-colors duration-500 ${gridClass} min-h-[300px] md:min-h-0 bg-dark-800`}
              >
                <Image
                  src={image.image}
                  alt={image.title}
                  fill
                  className="object-cover scale-105 group-hover:scale-100 transition-transform duration-700 brightness-90 group-hover:brightness-100"
                />
                {/* Dark Overlay Gradient */}
                <div className="absolute inset-0 bg-gradient-to-t from-dark-900 via-dark-900/40 to-transparent opacity-80 group-hover:opacity-60 transition-opacity duration-500" />

                {/* Content */}
                <div className="absolute inset-0 p-6 flex flex-col justify-end transform translate-y-4 group-hover:translate-y-0 transition-transform duration-500">
                  <h3 className="text-white text-2xl font-serif font-bold mb-1 opacity-0 group-hover:opacity-100 transition-opacity duration-500 delay-100">
                    {image.title}
                  </h3>
                  <span className="text-accent-gold text-sm tracking-widest uppercase opacity-0 group-hover:opacity-100 transition-opacity duration-500 delay-200">
                    {image.category === 'bridal' ? 'Bridal Luxury' : 'Modern Essential'}
                  </span>
                </div>
              </motion.div>
            );
          })}
        </div>

        {/* CTA */}
        <motion.div
          initial={{ opacity: 0, y: 20 }}
          whileInView={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8, delay: 0.4 }}
          className="mt-16 text-center"
        >
          <Button href="/gallery" variant="outline" size="lg" className="px-10 py-4 hover:bg-dark-800">
            View Complete Gallery
          </Button>
        </motion.div>
      </div>
    </section>
  );
}

'use client';

import { motion } from 'framer-motion';
import { SectionHeading } from '@/components/ui/SectionHeading';

const testimonials = [
  {
    name: 'Priya Sharma',
    role: 'Bride',
    text: 'Kartik and his team created the most stunning, intricate design for my wedding. The stain was incredibly dark and lasted for weeks. Highly recommended for any bride looking for perfection!',
    rating: 5,
    image: 'https://i.pravatar.cc/150?u=priya'
  },
  {
    name: 'Anjali Desai',
    role: 'Bridesmaid',
    text: 'The attention to detail is unmatched. They incorporated all the traditional elements we wanted while keeping the overall look very modern and chic. A truly premium experience.',
    rating: 5,
    image: 'https://i.pravatar.cc/150?u=anjali'
  },
  {
    name: 'Sneha Patel',
    role: 'Event Client',
    text: 'Professional, punctual, and beautifully artistic. The team made our family event so special with their quick yet flawless mehendi application. The dark theme of this website suits their premium service perfectly!',
    rating: 5,
    image: 'https://i.pravatar.cc/150?u=sneha'
  },
  {
    name: 'Riya Gupta',
    role: 'Bride',
    text: 'I was very particular about the symmetry in my bridal mehendi. Kartik listened to every detail and executed it beyond my expectations. Five stars are not enough!',
    rating: 5,
    image: 'https://i.pravatar.cc/150?u=riya'
  }
];

const StarRating = ({ rating }: { rating: number }) => {
  return (
    <div className="flex text-accent-gold mb-4">
      {[...Array(rating)].map((_, i) => (
        <svg key={i} xmlns="http://www.w3.org/2000/svg" className="h-5 w-5 fill-current" viewBox="0 0 24 24">
          <path d="M12 .587l3.668 7.568 8.332 1.151-6.064 5.828 1.48 8.279-7.416-3.967-7.417 3.967 1.481-8.279-6.064-5.828 8.332-1.151z" />
        </svg>
      ))}
    </div>
  );
};

export function Testimonials() {
  return (
    <section className="bg-dark-900 py-24 relative overflow-hidden">
      {/* Background glow accent */}
      <div className="absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[800px] h-[800px] bg-accent-gold/5 rounded-full blur-[100px] pointer-events-none"></div>

      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 relative z-10">
        <SectionHeading 
          title="Client Love" 
          subtitle="Testimonials" 
          description="Read what our brides and clients have to say about their premium mehendi experience."
        />

        <div className="mt-16 grid gap-8 md:grid-cols-2">
          {testimonials.map((testimonial, index) => (
            <motion.div 
              key={index}
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true, margin: '-50px' }}
              transition={{ delay: index * 0.1, duration: 0.6 }}
              className="bg-dark-800 border border-dark-700 p-8 rounded-2xl hover:border-accent-gold/30 hover:shadow-[0_0_25px_rgba(242,227,198,0.1)] transition-all duration-300"
            >
              <StarRating rating={testimonial.rating} />
              <p className="font-serif text-lg text-gray-300 leading-relaxed italic mb-8">
                &quot;{testimonial.text}&quot;
              </p>

              <div className="flex items-center">
                <img 
                  src={testimonial.image} 
                  alt={testimonial.name} 
                  className="w-12 h-12 rounded-full border-2 border-accent-bronze/50 object-cover"
                />
                <div className="ml-4">
                  <h4 className="font-bold text-white tracking-wide">{testimonial.name}</h4>
                  <p className="text-sm text-accent-gold/80">{testimonial.role}</p>
                </div>
              </div>
            </motion.div>
          ))}
        </div>
      </div>
    </section>
  );
}
